# Utility module providing base counter functionality
class CounterBase:
    _count: int

    def __init__(self):
        self._count = 0

    @virtual
    def increment(self) -> None:
        self._count = self._count + 1

    @virtual
    def get_value(self) -> int:
        return self._count

    def __str__(self) -> str:
        return "Count: " + str(self._count)

def double_value(x: int) -> int:
    return x * 2

